<#
.SYNOPSIS
    Configures a Windows lab VM to run OpenCode as the "TechCamp-Opencode" Okta-governed
    AI agent, reaching backend MCP tools only through the Okta Agent MCP Adapter ("the bridge").

.DESCRIPTION
    CONFIGURE-ONLY (does not provision the VM). Idempotent. Run on a vanilla Windows VM:

      1. Installs Node.js LTS (winget -> choco -> direct MSI fallback) and OpenCode (npm).
      2. Sets the OpenAI API key (OpenCode's model provider) at the chosen env scope.
      3. Writes opencode.json pointing at the adapter ROOT (not /mcp), tagging every request
         with X-MCP-Agent so Okta resolves this client to the named TechCamp-Opencode agent.
      4. Enables RDP (so the lab user can complete the one-time browser login on-box).
      5. Drops launch + authenticate helper shortcuts.

    OpenCode authenticates to the ADAPTER via the standard MCP OAuth flow (Dynamic Client
    Registration + auth-code/PKCE, loopback callback http://127.0.0.1:19876/...). The adapter
    is the OAuth server from OpenCode's perspective and brokers the login to Okta itself, so
    NO Okta client_id/secret goes in opencode.json. The agent is *named* via the X-MCP-Agent
    header, which the adapter resolves to the imported Okta AI Agent (principal_id agt...).

.PREREQUISITES (Okta / adapter side - see README.md)
    - Okta AI Agent "TechCamp-Opencode" (wlp24fnititUIJG4o1d8) registered + ACTIVE, with a
      Managed Connection granting the desired backend scopes.
    - That agent IMPORTED into the adapter and LINKED to the lab backend resource, so the
      X-MCP-Agent header resolves and tools/list returns tools. Without this, the tool list
      is empty even after a successful login.

.PARAMETER OpenAIApiKey
    OpenAI API key for the model provider. Injected by the lab (param, secret store, or -FromSsm).

.EXAMPLE
    .\Configure-OpenCodeAgent.ps1 -OpenAIApiKey $env:LAB_OPENAI_KEY -AgentName "TechCamp-Opencode"

.EXAMPLE
    # Pull secrets from SSM SecureString (only if the VM is in the taskvantage AWS account):
    .\Configure-OpenCodeAgent.ps1 -FromSsm -OpenAIApiKeyParam "/o4aa/opencode-agent/openai-api-key"

.EXAMPLE
    # Separate-bridge lab model: each VM finds its OWN paired bridge by EC2 tag and
    # reaches it over the fixed internal-HTTPS name (no public DNS, no Elastic IP).
    # Requires the bridge's ca.crt next to this script and an instance-profile with
    # ec2:DescribeInstances. See BRIDGE-DISCOVERY.md.
    .\Configure-OpenCodeAgent.ps1 -OpenAIApiKey $env:LAB_OPENAI_KEY -UseBridgeDiscovery
#>
[CmdletBinding()]
param(
    [string]$AdapterUrl  = "https://adapter.supersafe-ai.io",   # ROOT, not /mcp
    [string]$AgentName   = "TaskVantage Sales Agent",           # X-MCP-Agent (Action 7 re-points this to the real adapter slug post-import)
    [string]$Model       = "openai/gpt-4o",
    [string]$OpenAIApiKey,
    [ValidateSet("User","Machine")]
    [string]$EnvScope    = "Machine",
    [string]$WorkDir     = "C:\opencode-agent",
    [switch]$EnableRdp    = $true,
    # Remove base-image desktop clutter: keep ONLY the lab icons + browser, move
    # every other loose desktop shortcut to a reversible backup folder. Set
    # -CleanDesktop:$false to leave the desktop untouched.
    [switch]$CleanDesktop = $true,
    # Optional: read secrets from SSM SecureString instead of -OpenAIApiKey (in-account VMs only)
    [switch]$FromSsm,
    [string]$OpenAIApiKeyParam = "/o4aa/opencode-agent/openai-api-key",
    [string]$AwsRegion   = "us-east-2",

    # --- Separate-bridge (internal-HTTPS lab model) --------------------------
    # The VM reaches its OWN paired adapter bridge over the fixed name
    # adapter.taskvantage.lab; -BridgeAddress (below) supplies the private IP for
    # the hosts entry, and the CA is fetched from the bridge at runtime.
    [string]$AdapterHost = "adapter.taskvantage.lab",
    # Optional pre-shipped CA file; if absent the CA is fetched from the bridge.
    [string]$CaCertPath  = (Join-Path $PSScriptRoot "ca.crt"),
    # Friendly name for the bridge Admin UI (the "bridge GUI", a web console on :3001). Lab users
    # reach it at http://$BridgeGuiHost:$BridgeGuiPort via a hosts entry -> the SAME paired-bridge IP
    # as $AdapterHost. The configurator writes the hosts entry, a browser bookmark (all-users managed
    # policy), and a desktop shortcut. NB: http://$BridgeGuiHost:$BridgeGuiPort/callback must be a
    # registered redirect URI on the admin-ui OIDC app (provision_lab_org.py) or Admin-UI sign-in fails.
    [string]$BridgeGuiHost = "bridge.taskvantage.lab",
    [int]$BridgeGuiPort    = 3001,

    # --- Lab Toolkit (the on-VDI read/check menu utility) --------------------
    # Installs Lab-Toolkit.ps1 + toolkit.config.json to C:\LabToolkit and drops a
    # desktop shortcut. The toolkit mints per-persona tokens via the no-browser flow,
    # so it needs the lab-toolkit OIDC client_id + the vantage-crm-as id from provisioning.
    [switch]$InstallToolkit,
    [string]$OrgUrl,                                  # e.g. https://demo-...okta.com  (derived from -OrgSubdomain if omitted)
    [string]$ToolkitClientId,                         # lab-toolkit OIDC client_id (auto-resolved by name if omitted)
    [string]$CrmAsId,                                 # vantage-crm-as id (auto-resolved by audience if omitted)
    [string]$DeskAsId       = "",                     # vantage-desk-as id - blank until Module 4
    [string]$CrmHost        = "https://crm.taskvantage.oktademo.app",
    [string]$DeskHost       = "https://desk.taskvantage.oktademo.app",
    [string]$McpHost        = "mcp-crm.taskvantage.oktademo.app",   # per-app CRM MCP server; setup-crm wires the CRM resource to /mcp here (Desk uses mcp-desk.taskvantage.oktademo.app, wired by hand in Lab 4)
    [string]$PersonaPassword,                         # shared lab persona password
    [string]$ToolkitDir     = "C:\LabToolkit",

    # --- Subdomain-driven setup (attendee enters only their Okta subdomain) ---
    # The attendee supplies their subdomain; the per-org ids (lab-toolkit client,
    # vantage-crm-as, okta-mcp-admin-ui) are RESOLVED at runtime: the admin-ui client
    # id is read from the paired bridge's admin-ui config.js, then a one-time admin
    # sign-in (no-browser brokered flow) resolves the toolkit client + crm-as by
    # name/audience. Nothing per-org is baked into the image.
    [string]$OrgSubdomain,                            # e.g. demo-o4aa-techcamp-1  (-> https://<sub>.okta.com)
    [string]$OrgDomainSuffix = "okta.com",            # oktapreview.com for preview orgs
    # Paired-bridge private IP -> the adapter.taskvantage.lab + bridge.taskvantage.lab hosts entries.
    # Heropa places every user's bridge at a FIXED 10.0.0.5 and doesn't advertise it (nothing to pull
    # at runtime), so it's defaulted here. Pass -BridgeAddress '' to disable the whole bridge setup
    # (hosts entries, CA trust, adapter-URL override, GUI bookmark/shortcut) e.g. for the non-lab path.
    [string]$BridgeAddress = "10.0.0.5",
    [string]$AdminLogin,                              # attendee Okta admin login for the one-time resolve sign-in (prompted if omitted)
    [securestring]$AdminPassword,                     # admin password (prompted securely if omitted)
    [string]$AdminUiClientId,                         # okta-mcp-admin-ui client_id (else read from the bridge config.js)
    # --- Launcher-driven bridge bring-up (see lab-infra/BRIDGE-LAUNCHER-API-SPEC.md) ---
    # When set, the VDI configures + starts its paired bridge at run time; the bridge boots bare/idle
    # and this hands it the org identity. Requires -AdminUiClientId (platform-injected, since we cannot
    # read config.js from a bridge that is not up yet).
    [switch]$LaunchBridge,
    [int]$BridgeLauncherPort     = 9090,
    [string]$BridgeLauncherSecret,
    [int]$BridgeLaunchTimeoutSec = 120
)

$ErrorActionPreference = "Stop"
[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

# Set only in bridge mode (a paired bridge exists); section 6 drops a desktop shortcut when set.
$BridgeGuiUrl = $null

$LogFile = Join-Path $env:TEMP "configure-opencode-agent.log"
function Log {
    param([string]$Message, [string]$Level = "INFO")
    $line = "{0} [{1}] {2}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss"), $Level, $Message
    $line | Tee-Object -FilePath $LogFile -Append | Out-Host
}

function Test-Command { param([string]$Name) [bool](Get-Command $Name -ErrorAction SilentlyContinue) }

function Refresh-Path {
    $env:Path = [Environment]::GetEnvironmentVariable("Path","Machine") + ";" +
                [Environment]::GetEnvironmentVariable("Path","User")
}

# ---------------------------------------------------------------------------
# Embedded companion scripts (base64). This configurator is SELF-CONTAINED: the
# Lab Toolkit and the Action-7 CRM helper are carried inline and written out at
# install time, so the only file to place on the VDI image is THIS one.
# (Base64, so there are no here-string delimiter collisions with the content.)
# ---------------------------------------------------------------------------
$EmbeddedLabToolkitB64 = ''
$EmbeddedSetupCrmB64   = ''

function Write-EmbeddedScript {
    param([Parameter(Mandatory)][string]$B64,[Parameter(Mandatory)][string]$DestPath)
    if ($B64 -like '@@*@@') { Log "Embedded payload for $DestPath not populated - build step skipped?" "WARN"; return $false }
    try {
        [IO.File]::WriteAllBytes($DestPath, [Convert]::FromBase64String($B64))
        Log "Wrote $DestPath ($([math]::Round((Get-Item $DestPath).Length/1KB,1)) KB)"; return $true
    } catch { Log "Failed to write $DestPath from embedded payload: $_" "WARN"; return $false }
}

function Get-BridgeCa {
    # Fetch the paired bridge's CA at runtime so no cert file ships with the VDI.
    # Each bridge generates its own CA (CN 'O4AA Lab Dev CA'); we open a TLS
    # connection to the adapter, capture the presented chain, and return the root
    # (or the leaf if only the leaf is sent). Returns an X509Certificate2 or $null.
    param([string]$HostName,[int]$Port = 8000)
    try {
        $tcp = New-Object Net.Sockets.TcpClient
        $tcp.Connect($HostName,$Port)
        $captured = $null
        $ssl = New-Object Net.Security.SslStream($tcp.GetStream(),$false,
                 [Net.Security.RemoteCertificateValidationCallback]{ param($s,$cert,$chain,$errs)
                    if ($chain -and $chain.ChainElements.Count -gt 0) {
                        $script:_bridgeChain = @($chain.ChainElements | ForEach-Object { $_.Certificate })
                    }
                    $true })
        # Pin TLS 1.2 explicitly: SslStream.AuthenticateAsClient(string) defaults to TLS 1.0 on
        # .NET Framework (PS 5.1) - the adapter only accepts 1.2/1.3, so the bare call gets its
        # handshake closed ("remote party has closed the transport stream"). The Tls12 SecurityProtocol
        # set above only governs HttpWebRequest, not raw SslStream.
        $ssl.AuthenticateAsClient($HostName, $null, [System.Security.Authentication.SslProtocols]::Tls12, $false)
        $leaf = New-Object Security.Cryptography.X509Certificates.X509Certificate2($ssl.RemoteCertificate)
        $ssl.Close(); $tcp.Close()
        $chain = $script:_bridgeChain
        if ($chain -and $chain.Count -gt 1) { return $chain[$chain.Count-1] }  # root of the presented chain
        return $leaf                                                            # only the leaf was sent - pin it
    } catch { Log "Could not fetch bridge CA from $HostName`:$Port - $_" "WARN"; return $null }
}

function Get-LabDesktop {
    # All-users desktop. CommonDesktopDirectory is correct under SYSTEM/SSM and
    # interactive alike; fall back to the literal path if it ever comes back empty.
    $d = [Environment]::GetFolderPath("CommonDesktopDirectory")
    if ([string]::IsNullOrWhiteSpace($d) -or -not (Test-Path $d)) { $d = "C:\Users\Public\Desktop" }
    if (-not (Test-Path $d)) { New-Item -ItemType Directory -Force -Path $d | Out-Null }
    return $d
}

function New-DesktopShortcut {
    # Create (overwrite) an all-users desktop shortcut and VERIFY it landed.
    # Never throws: returns $true/$false and logs a WARN on failure, so one bad
    # shortcut can neither abort the build nor silently ship a broken desktop.
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][string]$TargetPath,
        [string]$Arguments = "",
        [string]$WorkingDirectory = "",
        [string]$IconLocation = ""
    )
    $path = Join-Path (Get-LabDesktop) ($Name + ".lnk")
    try {
        $ws  = New-Object -ComObject WScript.Shell
        $lnk = $ws.CreateShortcut($path)
        $lnk.TargetPath = $TargetPath
        if ($Arguments)        { $lnk.Arguments        = $Arguments }
        if ($WorkingDirectory) { $lnk.WorkingDirectory = $WorkingDirectory }
        if ($IconLocation)     { $lnk.IconLocation     = $IconLocation }
        $lnk.Save()
        [Runtime.InteropServices.Marshal]::ReleaseComObject($ws) | Out-Null
        if (Test-Path $path) { Log "Desktop shortcut OK: $Name"; return $true }
        Log "Desktop shortcut '$Name' did not appear at $path" "WARN"; return $false
    } catch {
        Log "Desktop shortcut '$Name' failed: $_" "WARN"; return $false
    }
}

function New-UrlShortcut {
    # All-users desktop .url internet shortcut -> opens $Url in the default browser. A .url is the
    # natural shortcut type for a web address (double-click = open in browser). Never throws.
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][string]$Url
    )
    $path = Join-Path (Get-LabDesktop) ($Name + ".url")
    try {
        # ASCII, CRLF; [InternetShortcut] is the shell-recognised format.
        Set-Content -Path $path -Encoding ASCII -Value @("[InternetShortcut]", "URL=$Url")
        if (Test-Path $path) { Log "Desktop URL shortcut OK: $Name -> $Url"; return $true }
        Log "URL shortcut '$Name' did not appear at $path" "WARN"; return $false
    } catch {
        Log "URL shortcut '$Name' failed: $_" "WARN"; return $false
    }
}

function Set-ManagedBrowserBookmark {
    # Add a bookmarks-bar entry for ALL users via enterprise policy (no per-user profile needed,
    # survives image bake, no running-browser/checksum races). Edge = ManagedFavorites, Chrome =
    # ManagedBookmarks; both take a JSON array whose optional first element names the top-level
    # folder. Also enable the bookmarks/favorites bar so the entry is visible. Never throws.
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][string]$Url,
        [string]$Folder = "TaskVantage Lab"
    )
    $json = ConvertTo-Json @(@{ toplevel_name = $Folder }, @{ name = $Name; url = $Url }) -Compress
    $targets = @(
        @{ Browser = "Edge";   Path = "HKLM:\SOFTWARE\Policies\Microsoft\Edge"; Value = "ManagedFavorites"; BarValue = "FavoritesBarEnabled" },
        @{ Browser = "Chrome"; Path = "HKLM:\SOFTWARE\Policies\Google\Chrome";  Value = "ManagedBookmarks"; BarValue = "BookmarkBarEnabled" }
    )
    foreach ($t in $targets) {
        try {
            if (-not (Test-Path $t.Path)) { New-Item -Path $t.Path -Force | Out-Null }
            New-ItemProperty -Path $t.Path -Name $t.Value    -Value $json -PropertyType String -Force | Out-Null
            New-ItemProperty -Path $t.Path -Name $t.BarValue -Value 1     -PropertyType DWord  -Force | Out-Null
            Log "$($t.Browser) managed bookmark set: $Name -> $Url (folder '$Folder')"
        } catch { Log "$($t.Browser) managed bookmark failed: $_" "WARN" }
    }
}

Log "=== Configure-OpenCodeAgent starting (agent=$AgentName, adapter=$AdapterUrl) ==="

# ---------------------------------------------------------------------------
# 0. Resolve secrets
# ---------------------------------------------------------------------------
if ($FromSsm) {
    Log "Reading OpenAI key from SSM SecureString $OpenAIApiKeyParam (region $AwsRegion)"
    Import-Module AWS.Tools.SimpleSystemsManagement -ErrorAction Stop   # AWS Tools for PowerShell (not AWS CLI)
    $OpenAIApiKey = (Get-SSMParameter -Name $OpenAIApiKeyParam -WithDecryption $true -Region $AwsRegion).Value
}
if ([string]::IsNullOrWhiteSpace($OpenAIApiKey)) {
    throw "OpenAIApiKey is required (pass -OpenAIApiKey or -FromSsm). Aborting."
}

# ---------------------------------------------------------------------------
# 0a. Subdomain-driven setup: org URL, paired-bridge hosts entry, per-org ids
# ---------------------------------------------------------------------------
# The attendee supplies only their Okta subdomain. Per-org ids are resolved at
# runtime (convention + a one-time admin sign-in) so nothing per-org is baked in.
if ($OrgSubdomain -and -not $OrgUrl) {
    $OrgUrl = "https://$OrgSubdomain.$OrgDomainSuffix"
    Log "Derived OrgUrl from subdomain: $OrgUrl"
}

# Platform injects the paired bridge address -> adapter.taskvantage.lab hosts entry + trust CA.
if ($BridgeAddress) {
    $AdapterUrl = "https://$AdapterHost`:8000"
    Log "Paired bridge $BridgeAddress -> $AdapterHost ($AdapterUrl)"
    $hostsFile = "$env:windir\System32\drivers\etc\hosts"
    try {
        $keep = @()
        if (Test-Path $hostsFile) { $keep = Get-Content $hostsFile | Where-Object { $_ -notmatch "\s$([regex]::Escape($AdapterHost))(\s|$)" } }
        ($keep + "$BridgeAddress`t$AdapterHost") | Set-Content -Path $hostsFile -Encoding ASCII
        Log "Wrote hosts entry: $BridgeAddress $AdapterHost"
    } catch { Log "Could not write hosts entry: $_" "WARN" }

    # Friendly bridge-GUI name -> same paired-bridge IP, so lab users reach the Admin UI (port
    # $BridgeGuiPort) at a clean URL. Also add an all-users browser bookmark (managed policy). The
    # matching desktop shortcut is dropped in section 6 (once $BridgeGuiUrl is set below).
    $BridgeGuiUrl = "http://$BridgeGuiHost`:$BridgeGuiPort"
    try {
        $keepGui = @()
        if (Test-Path $hostsFile) { $keepGui = Get-Content $hostsFile | Where-Object { $_ -notmatch "\s$([regex]::Escape($BridgeGuiHost))(\s|$)" } }
        ($keepGui + "$BridgeAddress`t$BridgeGuiHost") | Set-Content -Path $hostsFile -Encoding ASCII
        Log "Wrote hosts entry: $BridgeAddress $BridgeGuiHost (bridge GUI)"
    } catch { Log "Could not write bridge-GUI hosts entry: $_" "WARN" }
    Set-ManagedBrowserBookmark -Name "Bridge Admin" -Url $BridgeGuiUrl

    # Launcher-driven bring-up: configure + start the paired bridge BEFORE we depend on it (the CA
    # fetch just below and the config.js read later both need the adapter up). The bridge boots
    # bare/idle running a small Launcher API; here we hand it the org identity so its adapter +
    # admin-ui come up. Plain HTTP by IP (pod-internal) - no hosts entry or CA needed for this call.
    # See lab-infra/BRIDGE-LAUNCHER-API-SPEC.md.
    if ($LaunchBridge) {
        if (-not $OrgUrl)               { throw "-LaunchBridge requires -OrgUrl (or -OrgSubdomain) to derive OKTA_DOMAIN." }
        if (-not $AdminUiClientId)      { throw "-LaunchBridge requires -AdminUiClientId (platform-injected; cannot be read from a bridge that is not up yet)." }
        if (-not $BridgeLauncherSecret) { throw "-LaunchBridge requires -BridgeLauncherSecret." }
        $lb     = "http://$BridgeAddress`:$BridgeLauncherPort"
        $domain = ([uri]$OrgUrl).Host
        $hdr    = @{ Authorization = "Bearer $BridgeLauncherSecret" }
        Log "Launching paired bridge via $lb (org $domain)"
        # 1. launcher alive?
        try { Invoke-RestMethod "$lb/healthz" -TimeoutSec 8 | Out-Null }
        catch { throw "Bridge launcher not reachable at $lb - is the bridge VM up? ($_)" }
        # 2. configure + start the stack
        try {
            $body = @{ okta_domain = $domain; admin_ui_client_id = $AdminUiClientId } | ConvertTo-Json -Compress
            Invoke-RestMethod "$lb/launch" -Method POST -Headers $hdr -ContentType "application/json" -Body $body -TimeoutSec 30 | Out-Null
            Log "Bridge launch requested; waiting for adapter + admin-ui to become healthy (up to $BridgeLaunchTimeoutSec s)..."
        } catch { throw "Bridge /launch failed: $_" }
        # 3. poll /status until both are healthy
        $deadline = (Get-Date).AddSeconds($BridgeLaunchTimeoutSec); $ready = $false
        do {
            Start-Sleep -Seconds 5
            try {
                $st = Invoke-RestMethod "$lb/status" -Headers $hdr -TimeoutSec 8
                Log "  bridge: adapter=$($st.adapter_ready) admin_ui=$($st.admin_ui_ready)"
                $ready = ([bool]$st.adapter_ready -and [bool]$st.admin_ui_ready)
            } catch { Log "  bridge status poll failed (retrying): $_" "WARN" }
        } until ($ready -or ((Get-Date) -gt $deadline))
        if (-not $ready) { throw "Bridge did not become healthy within $BridgeLaunchTimeoutSec s - check the bridge VM (docker compose ps / launcher logs)." }
        Log "Paired bridge is up and configured for $domain."
    }

    # Trust the bridge CA: prefer a shipped/passed ca.crt, else FETCH it from the paired bridge
    # at runtime (zero cert files ship with the VDI - the configurator is fully self-contained).
    $caForNode = $null
    if (Test-Path $CaCertPath) {
        try { $imp = Import-Certificate -FilePath $CaCertPath -CertStoreLocation Cert:\LocalMachine\Root; Log "Trusted lab CA (file): $($imp.Subject)"; $caForNode = $CaCertPath }
        catch { Log "CA import failed: $_" "WARN" }
    } else {
        Log "No local CA - fetching it from the paired bridge $AdapterHost ..."
        $bca = Get-BridgeCa -HostName $AdapterHost -Port 8000
        if ($bca) {
            try {
                $store = New-Object Security.Cryptography.X509Certificates.X509Store("Root","LocalMachine")
                $store.Open("ReadWrite"); $store.Add($bca); $store.Close()
                Log "Trusted bridge CA (fetched): $($bca.Subject)"
                New-Item -ItemType Directory -Force -Path $WorkDir | Out-Null
                $caForNode = Join-Path $WorkDir "lab-ca.crt"
                [IO.File]::WriteAllText($caForNode, "-----BEGIN CERTIFICATE-----`n" + [Convert]::ToBase64String($bca.RawData,'InsertLineBreaks') + "`n-----END CERTIFICATE-----`n")
            } catch { Log "Could not trust fetched bridge CA: $_" "WARN" }
        } else { Log "Bridge CA fetch failed - HTTPS to the bridge will fail until trusted." "WARN" }
    }
    # OpenCode (Node) uses its own CA bundle, not the Windows store - point it at the lab CA.
    if ($caForNode) {
        [Environment]::SetEnvironmentVariable("NODE_EXTRA_CA_CERTS",$caForNode,"Machine")
        $env:NODE_EXTRA_CA_CERTS = $caForNode
        Log "Set NODE_EXTRA_CA_CERTS=$caForNode (so OpenCode trusts the bridge)"
    }
}

# Resolve the per-org ids when the toolkit is requested and any is missing.
if ($InstallToolkit -and $OrgUrl -and ((-not $ToolkitClientId) -or (-not $CrmAsId) -or (-not $AdminUiClientId))) {
    Add-Type -AssemblyName System.Web
    function _B64Url([byte[]]$b){ [Convert]::ToBase64String($b).TrimEnd('=').Replace('+','-').Replace('/','_') }
    function _Web { param([string]$M,[string]$U,[string]$Body,[string]$CT,[hashtable]$H,[System.Net.CookieContainer]$Jar,[switch]$NoRedirect)
      $r=[System.Net.HttpWebRequest]::Create($U); $r.Method=$M; $r.AllowAutoRedirect=-not $NoRedirect
      if($Jar){$r.CookieContainer=$Jar}; $r.Accept="application/json"
      if($H){foreach($k in $H.Keys){ if($k -eq "Content-Type"){$r.ContentType=$H[$k]}else{$r.Headers[$k]=$H[$k]} }}
      if($Body){$r.ContentType=$CT;$by=[Text.Encoding]::UTF8.GetBytes($Body);$r.ContentLength=$by.Length;$s=$r.GetRequestStream();$s.Write($by,0,$by.Length);$s.Close()}
      try{$resp=$r.GetResponse();$loc=$resp.Headers["Location"];$c=[int]$resp.StatusCode;$sr=New-Object IO.StreamReader($resp.GetResponseStream());$t=$sr.ReadToEnd();$sr.Close();$resp.Close();return @{status=$c;body=$t;location=$loc}}
      catch [System.Net.WebException]{$resp=$_.Exception.Response; if(-not $resp){return @{status=-1;body=$_.Exception.Message;location=$null}}; $loc=$resp.Headers["Location"];$c=[int]$resp.StatusCode;$sr=New-Object IO.StreamReader($resp.GetResponseStream());$t=$sr.ReadToEnd();$sr.Close();return @{status=$c;body=$t;location=$loc}} }
    function _Json($t){ if($t){try{$t|ConvertFrom-Json}catch{$t}}else{$null} }

    # admin-ui client id from the paired bridge's public config.js (nothing per-org baked in)
    if (-not $AdminUiClientId) {
      try { $js=(_Web GET "http://$AdapterHost`:3001/config.js").body
            if ($js -match 'VITE_OKTA_CLIENT_ID:\s*"([^"]+)"') { $AdminUiClientId=$Matches[1]; Log "admin-ui client id (from bridge config.js): $AdminUiClientId" } }
      catch { Log "could not read bridge config.js: $_" "WARN" }
    }
    if (-not $AdminUiClientId) { throw "Need the okta-mcp-admin-ui client id (bridge config.js unreachable) - pass -AdminUiClientId." }

    # one-time admin sign-in (no-browser brokered flow; admin-ui is NOMFA-mapped). TOTP handled if challenged.
    if (-not $AdminLogin)    { $AdminLogin = Read-Host "Okta admin login (one-time, to resolve this org's ids)" }
    if (-not $AdminPassword) { $AdminPassword = Read-Host "Okta admin password" -AsSecureString }
    $plain=[Runtime.InteropServices.Marshal]::PtrToStringAuto([Runtime.InteropServices.Marshal]::SecureStringToBSTR($AdminPassword))
    $jar=New-Object System.Net.CookieContainer
    $an=_Json (_Web POST "$OrgUrl/api/v1/authn" (@{username=$AdminLogin;password=$plain}|ConvertTo-Json) "application/json" $null $jar).body
    if ($an.status -eq "MFA_REQUIRED") {
      $f=$an._embedded.factors | Where-Object { $_.factorType -eq "token:software:totp" } | Select-Object -First 1
      if (-not $f) { throw "admin MFA required but no TOTP factor for the no-browser flow." }
      $passcode=Read-Host "Admin MFA (TOTP) code"
      $an=_Json (_Web POST $f._links.verify.href (@{stateToken=$an.stateToken;passCode=$passcode}|ConvertTo-Json) "application/json" $null $jar).body
    }
    if ($an.status -ne "SUCCESS" -or -not $an.sessionToken) { throw "admin sign-in failed (status=$($an.status))." }
    _Web GET "$OrgUrl/login/sessionCookieRedirect?token=$([uri]::EscapeDataString($an.sessionToken))&redirectUrl=$([uri]::EscapeDataString("$OrgUrl/app/UserHome"))" $null $null $null $jar -NoRedirect | Out-Null

    $vb=New-Object byte[] 48; [Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($vb); $v=_B64Url $vb
    $ch=_B64Url ([Security.Cryptography.SHA256]::Create().ComputeHash([Text.Encoding]::ASCII.GetBytes($v)))
    $st=[Guid]::NewGuid().ToString("N"); $redir="http://localhost:3001/callback"
    $auth="$OrgUrl/oauth2/v1/authorize?response_type=code&client_id=$AdminUiClientId&redirect_uri=$([uri]::EscapeDataString($redir))&scope=$([uri]::EscapeDataString('openid okta.apps.read okta.authorizationServers.read'))&state=$st&code_challenge=$ch&code_challenge_method=S256"
    $url=$auth; $acode=$null
    for($i=0;$i -lt 12;$i++){ $r=_Web GET $url $null $null $null $jar -NoRedirect; if(-not $r.location){throw "authorize stopped HTTP $($r.status) (MFA/consent?)"}; $loc=$r.location; if($loc.StartsWith("/")){$loc=([uri]$url).GetLeftPart([UriPartial]::Authority)+$loc}; if($loc.StartsWith($redir)){$q=[System.Web.HttpUtility]::ParseQueryString(([uri]$loc).Query); if($q["error"]){throw "authorize: $($q['error'])"}; $acode=$q["code"]; break}; $url=$loc }
    if(-not $acode){throw "admin authorize did not reach the callback."}
    $tok=_Json (_Web POST "$OrgUrl/oauth2/v1/token" "grant_type=authorization_code&code=$acode&redirect_uri=$([uri]::EscapeDataString($redir))&client_id=$AdminUiClientId&code_verifier=$v" "application/x-www-form-urlencoded" $null $null).body
    $admTok=$tok.access_token
    if(-not $admTok){throw "admin token exchange failed: $($tok|ConvertTo-Json -Compress)"}

    if (-not $ToolkitClientId) {
      $apps=_Json (_Web GET "$OrgUrl/api/v1/apps?q=$([uri]::EscapeDataString('O4AA Lab Toolkit'))&limit=20" $null $null @{Authorization="Bearer $admTok"}).body
      $tk=$apps | Where-Object { $_.label -eq "O4AA Lab Toolkit" } | Select-Object -First 1
      if($tk){ $ToolkitClientId=$tk.credentials.oauthClient.client_id; Log "Resolved toolkit_client_id: $ToolkitClientId" }
    }
    if (-not $CrmAsId) {
      $ases=_Json (_Web GET "$OrgUrl/api/v1/authorizationServers?limit=200" $null $null @{Authorization="Bearer $admTok"}).body
      $as=$ases | Where-Object { $_.audiences -contains "api://vantage-crm" } | Select-Object -First 1
      if($as){ $CrmAsId=$as.id; Log "Resolved crm_as_id: $CrmAsId" }
    }
}


# ---------------------------------------------------------------------------
# 0c. Lab Toolkit (on-VDI read/check menu)
# ---------------------------------------------------------------------------
if ($InstallToolkit) {
    Log "Installing Lab Toolkit to $ToolkitDir"
    $missing = @()
    foreach ($pair in @(@{n="-OrgUrl";v=$OrgUrl}, @{n="-ToolkitClientId";v=$ToolkitClientId},
                        @{n="-CrmAsId";v=$CrmAsId}, @{n="-PersonaPassword";v=$PersonaPassword})) {
        if ([string]::IsNullOrWhiteSpace($pair.v)) { $missing += $pair.n }
    }
    if ($missing.Count) { Log "Lab Toolkit needs: $($missing -join ', ') - skipping toolkit install." "WARN" }
    else {
        $tkAdapter = if ($AdapterHost) { "https://$AdapterHost`:8000" } else { $AdapterUrl }
        New-Item -ItemType Directory -Force -Path $ToolkitDir | Out-Null
        # Write the embedded companion scripts (self-contained - nothing ships beside this file).
        Write-EmbeddedScript -B64 $EmbeddedLabToolkitB64 -DestPath (Join-Path $ToolkitDir "Lab-Toolkit.ps1") | Out-Null
        if (-not (Write-EmbeddedScript -B64 $EmbeddedSetupCrmB64 -DestPath (Join-Path $ToolkitDir "setup-crm-resource.ps1"))) {
            Log "Action 7 (setup-crm-resource) unavailable - embedded payload missing." "WARN"
        }
        $caFile = if ($caForNode) { $caForNode } elseif (Test-Path $CaCertPath) { $CaCertPath } else { $null }
        if ($caFile -and (Test-Path $caFile)) { Copy-Item -Path $caFile -Destination (Join-Path $ToolkitDir "lab-ca.crt") -Force }

        $cfg = [ordered]@{
            org_url = $OrgUrl; adapter_url = $tkAdapter; agent_header = $AgentName
            toolkit_client_id = $ToolkitClientId; crm_as_id = $CrmAsId; desk_as_id = $DeskAsId
            admin_ui_client_id = $AdminUiClientId          # Action 7 mints an admin token against this
            agent_name = $AgentName                        # Okta AI-agent display name Action 7 resolves
            mcp_host = $McpHost                            # per-app CRM MCP host the CRM resource is wired to (/mcp)
            opencode_config = (Join-Path $WorkDir "opencode.json")  # Action 7 re-points X-MCP-Agent here
            crm_host = $CrmHost; desk_host = $DeskHost; persona_password = $PersonaPassword
            read_scopes_crm = @("crm.accounts.read","crm.contacts.read","crm.opportunities.read")
            read_scopes_desk = @("itsm.tickets.read","itsm.incidents.read","itsm.kb.read")
            personas = @(
                [ordered]@{key="alex"; login="alex.martinez@atko.email"; label="Alex Martinez (Sales Rep)"},
                [ordered]@{key="susan";login="susan.potter@atko.email";  label="Susan Potter (Sales Manager)"},
                [ordered]@{key="kim";  login="kim.liu@atko.email";       label="Kim Liu (IT Help Desk)"},
                [ordered]@{key="frank";login="frank.boone@atko.email";   label="Frank Boone (Engineering)"})
        }
        $cfg | ConvertTo-Json -Depth 6 | Set-Content -Path (Join-Path $ToolkitDir "toolkit.config.json") -Encoding UTF8
        Log "Wrote $ToolkitDir\toolkit.config.json (adapter=$tkAdapter, client=$ToolkitClientId)"

        New-DesktopShortcut -Name "Lab Toolkit" -TargetPath "powershell.exe" `
            -Arguments "-NoExit -ExecutionPolicy Bypass -File `"$ToolkitDir\Lab-Toolkit.ps1`"" `
            -WorkingDirectory $ToolkitDir -IconLocation "powershell.exe,0" | Out-Null
    }
}

# ---------------------------------------------------------------------------
# 1. Node.js LTS (require major >= 20 for current opencode-ai)
# ---------------------------------------------------------------------------
$MinNodeMajor = 20
Refresh-Path
# Determine whether a new-enough Node is already installed. The Heropa VDI ships
# Node v16, which is too old for current opencode-ai (needs 20+), so "node is on
# PATH" is NOT sufficient - we must also check the major version and UPGRADE when
# it is below $MinNodeMajor.
$nodeOk = $false
if (Test-Command node) {
    $nodeVer = (node -v) 2>$null            # e.g. "v16.20.0"
    if ($nodeVer -match '^v?(\d+)\.') {
        $nodeMajor = [int]$Matches[1]
        if ($nodeMajor -ge $MinNodeMajor) {
            $nodeOk = $true
            Log "Node already present and new enough: $nodeVer (major $nodeMajor >= $MinNodeMajor)"
        } else {
            Log "Node $nodeVer is too old (major $nodeMajor < $MinNodeMajor) - upgrading to Node $MinNodeMajor LTS..." "WARN"
        }
    } else {
        Log "Could not parse Node version '$nodeVer' - reinstalling Node $MinNodeMajor LTS to be safe..." "WARN"
    }
}
if ($nodeOk) {
    # nothing to do
} else {
    Log "Installing Node.js LTS..."
    $installed = $false
    if (Test-Command winget) {
        try { winget install --id OpenJS.NodeJS.LTS -e --silent --accept-source-agreements --accept-package-agreements; $installed = $true }
        catch { Log "winget Node install failed: $_" "WARN" }
    }
    if (-not $installed -and (Test-Command choco)) {
        try { choco install nodejs-lts -y; $installed = $true } catch { Log "choco Node install failed: $_" "WARN" }
    }
    if (-not $installed) {
        $msi = Join-Path $env:TEMP "node-lts.msi"
        Log "Falling back to direct Node LTS MSI download"
        Invoke-WebRequest -Uri "https://nodejs.org/dist/latest-v20.x/node-v20.20.2-x64.msi" -OutFile $msi -UseBasicParsing
        Start-Process msiexec.exe -ArgumentList "/i `"$msi`" /quiet /norestart" -Wait
    }
    Refresh-Path
    if (-not (Test-Command node)) { throw "Node install failed; node not on PATH." }
    $newVer = (node -v) 2>$null
    if ($newVer -match '^v?(\d+)\.' -and [int]$Matches[1] -lt $MinNodeMajor) {
        throw "Node upgrade did not take effect; 'node -v' is still $newVer (need major >= $MinNodeMajor). An older Node may be ahead on PATH."
    }
    Log "Node installed: $newVer"
}

# ---------------------------------------------------------------------------
# 2. OpenCode  (machine-wide npm prefix so it's found by every account -
#    SSM/SYSTEM during build AND the interactive RDP user later)
# ---------------------------------------------------------------------------
$NpmPrefix = "C:\ProgramData\npm-global"
$OpenCodeExe = Join-Path $NpmPrefix "opencode.cmd"
Refresh-Path
if (Test-Path $OpenCodeExe) {
    Log "OpenCode already present: $(& $OpenCodeExe --version)"
} else {
    Log "Installing OpenCode (npm prefix $NpmPrefix)..."
    New-Item -ItemType Directory -Force -Path $NpmPrefix | Out-Null
    & npm config set prefix $NpmPrefix --global
    & npm install -g opencode-ai
    # ensure the prefix is on the *Machine* PATH for all users
    $mp = [Environment]::GetEnvironmentVariable("Path","Machine")
    if ($mp -notlike "*$NpmPrefix*") {
        [Environment]::SetEnvironmentVariable("Path", "$mp;$NpmPrefix", "Machine")
        Log "Added $NpmPrefix to Machine PATH"
    }
    Refresh-Path
    if (-not (Test-Path $OpenCodeExe)) { throw "OpenCode install failed; $OpenCodeExe not found." }
    Log "OpenCode installed: $(& $OpenCodeExe --version)"
}

# ---------------------------------------------------------------------------
# 3. OpenAI API key (model provider) - never logged
# ---------------------------------------------------------------------------
Log "Setting OPENAI_API_KEY ($EnvScope scope)"
[Environment]::SetEnvironmentVariable("OPENAI_API_KEY", $OpenAIApiKey, $EnvScope)
$env:OPENAI_API_KEY = $OpenAIApiKey   # current session

# ---------------------------------------------------------------------------
# 4. opencode.json
# ---------------------------------------------------------------------------
New-Item -ItemType Directory -Force -Path $WorkDir | Out-Null
$config = [ordered]@{
    '$schema' = "https://opencode.ai/config.json"
    model     = $Model
    mcp       = [ordered]@{
        'okta-bridge' = [ordered]@{
            type    = "remote"
            url     = $AdapterUrl                     # ROOT - the adapter's MCP endpoint is /
            enabled = $true
            headers = [ordered]@{ 'X-MCP-Agent' = $AgentName }
            # No oauth.clientId -> OpenCode dynamically registers a loopback client with the
            # adapter (RFC 7591); the adapter brokers the login to Okta. The named-agent identity
            # comes from the X-MCP-Agent header above.
        }
    }
}
$configPath = Join-Path $WorkDir "opencode.json"
$config | ConvertTo-Json -Depth 8 | Set-Content -Path $configPath -Encoding UTF8
# Restrict ACLs (defense in depth; no secrets in this file, but keep it tidy)
Log "Wrote $configPath"

# ---------------------------------------------------------------------------
# 5. RDP (for the one-time browser login)
# ---------------------------------------------------------------------------
if ($EnableRdp) {
    Log "Enabling RDP"
    # Non-fatal: a registry/firewall hiccup must not abort the run before the
    # desktop shortcuts below get created (that was the section-6 skip bug).
    try {
        Set-ItemProperty -Path 'HKLM:\System\CurrentControlSet\Control\Terminal Server' -Name "fDenyTSConnections" -Value 0 -ErrorAction Stop
        Enable-NetFirewallRule -DisplayGroup "Remote Desktop" -ErrorAction SilentlyContinue
        Log "RDP enabled"
    } catch { Log "RDP enable failed (continuing): $_" "WARN" }
}

# ---------------------------------------------------------------------------
# 6. Helper shortcuts  (Start OpenCode + Authenticate Okta Bridge)
#    .cmd writes are wrapped; each shortcut falls back to a self-contained
#    PowerShell command if its .cmd is missing, so the icon always works.
# ---------------------------------------------------------------------------
$startCmd = Join-Path $WorkDir "Start-OpenCode.cmd"
$authCmd  = Join-Path $WorkDir "Authenticate-OktaBridge.cmd"
try {
    New-Item -ItemType Directory -Force -Path $WorkDir | Out-Null
    "@echo off`r`ncd /d `"$WorkDir`"`r`nopencode`r`n" | Set-Content -Path $startCmd -Encoding ASCII
    "@echo off`r`ncd /d `"$WorkDir`"`r`nopencode mcp auth okta-bridge`r`npause`r`n" | Set-Content -Path $authCmd -Encoding ASCII
} catch { Log "Writing helper .cmd files failed (will use PowerShell fallback): $_" "WARN" }

if (Test-Path $startCmd) {
    New-DesktopShortcut -Name "Start OpenCode" -TargetPath $startCmd -WorkingDirectory $WorkDir | Out-Null
} else {
    New-DesktopShortcut -Name "Start OpenCode" -TargetPath "powershell.exe" `
        -Arguments "-NoExit -Command `"cd '$WorkDir'; opencode`"" -WorkingDirectory $WorkDir | Out-Null
}
if (Test-Path $authCmd) {
    New-DesktopShortcut -Name "Authenticate Okta Bridge" -TargetPath $authCmd -WorkingDirectory $WorkDir | Out-Null
} else {
    New-DesktopShortcut -Name "Authenticate Okta Bridge" -TargetPath "powershell.exe" `
        -Arguments "-NoExit -Command `"cd '$WorkDir'; opencode mcp auth okta-bridge`"" -WorkingDirectory $WorkDir | Out-Null
}

# Bridge GUI (Admin UI) - one-click access to the bridge console. Only in bridge mode.
if ($BridgeGuiUrl) {
    New-UrlShortcut -Name "Bridge Admin" -Url $BridgeGuiUrl | Out-Null
}

# ---------------------------------------------------------------------------
# 6b. Clean pre-existing desktop clutter  (allowlist; reversible move-to-backup)
#     Keep ONLY the lab icons + the browser; move every other loose desktop
#     shortcut (.lnk/.url/.website) to a backup folder. Runs AFTER the lab
#     shortcuts are created so they're protected by the keep-list. Folders
#     (logs, Microsoft) and desktop.ini are never touched; apps are never
#     uninstalled - only the desktop icon is moved.
# ---------------------------------------------------------------------------
if ($CleanDesktop) {
    $keepIcons  = @("Lab Toolkit.lnk","Start OpenCode.lnk","Authenticate Okta Bridge.lnk","Google Chrome.lnk","Bridge Admin.url")
    $clutterExt = @(".lnk",".url",".website")
    $backupRoot = "C:\_removed-desktop-icons"
    # All-users desktop, every per-user desktop, AND the hidden Default profile.
    # Default\Desktop seeds every NEWLY created profile (e.g. an attendee's first
    # RDP login), so if we skip it the base-image clutter reappears on fresh
    # profiles. Get-ChildItem -Directory (no -Force) does NOT enumerate the hidden
    # Default profile, so add it explicitly.
    $deskDirs = @((Get-LabDesktop))
    $deskDirs += @(Get-ChildItem C:\Users -Directory -ErrorAction SilentlyContinue |
                   ForEach-Object { Join-Path $_.FullName "Desktop" } | Where-Object { Test-Path $_ })
    $defaultDesk = Join-Path $env:SystemDrive "Users\Default\Desktop"
    if (Test-Path $defaultDesk) { $deskDirs += $defaultDesk }
    $movedCount = 0
    foreach ($dir in ($deskDirs | Select-Object -Unique)) {
        Get-ChildItem $dir -File -Force -ErrorAction SilentlyContinue | ForEach-Object {
            if (($clutterExt -contains $_.Extension.ToLower()) -and ($keepIcons -notcontains $_.Name)) {
                try {
                    New-Item -ItemType Directory -Force -Path $backupRoot | Out-Null
                    Move-Item -LiteralPath $_.FullName -Destination (Join-Path $backupRoot $_.Name) -Force
                    $movedCount++
                    Log "Desktop cleanup: moved '$($_.Name)' (from $dir)"
                } catch { Log "Desktop cleanup: could not move '$($_.Name)': $_" "WARN" }
            }
        }
    }
    Log "Desktop cleanup complete - moved $movedCount clutter icon(s) to $backupRoot (reversible; apps untouched)."
}

# ---------------------------------------------------------------------------
# 6c. Verify the lab desktop  (fail loud in the build log; never ship broken)
# ---------------------------------------------------------------------------
$expectedIcons = @("Start OpenCode","Authenticate Okta Bridge")
if ($InstallToolkit) { $expectedIcons = @("Lab Toolkit") + $expectedIcons }
$deskDir = Get-LabDesktop
$missingIcons = @($expectedIcons | Where-Object { -not (Test-Path (Join-Path $deskDir "$_.lnk")) })
if ($missingIcons.Count) {
    Log "DESKTOP VERIFY FAILED - missing icon(s): $($missingIcons -join ', '). The lab desktop is incomplete." "WARN"
} else {
    Log "DESKTOP VERIFY OK - all lab icons present: $($expectedIcons -join ', ')."
}

# ---------------------------------------------------------------------------
# 7. Next steps
# ---------------------------------------------------------------------------
Log "=== Configuration complete ==="
Write-Host ""
Write-Host "NEXT STEPS (run in an RDP session as the lab user):" -ForegroundColor Cyan
Write-Host "  1. Double-click 'Authenticate Okta Bridge' (or run:  opencode mcp auth okta-bridge )"
Write-Host "     A browser opens to taskvantage.okta.com - sign in as the entitled lab user."
Write-Host "  2. Verify:  opencode mcp list      (okta-bridge should show connected)"
Write-Host "  3. Launch:  Start OpenCode         then ask it to list/use its tools."
Write-Host ""
Write-Host "If tools/list is empty after login: the TechCamp-Opencode agent is not yet IMPORTED"
Write-Host "+ LINKED to a backend resource in the adapter. See README.md (adapter-side setup)."
